const body = $input.first().json.body;
const events = body?.events || [];

if (!events.length) return [];

const event = events[0];
if (event.type !== "message") return [];

const msg = event.message;
const esc = (s) => String(s || '').replace(/'/g, "''");

let text = '';
switch(msg.type) {
  case 'text': text = msg.text; break;
  case 'sticker': text = '[สติกเกอร์]'; break;
  case 'image': text = '[รูปภาพ]'; break;
  case 'video': text = '[วิดีโอ]'; break;
  case 'audio': text = '[เสียง]'; break;
  case 'location': text = '[ตำแหน่ง] ' + (msg.address || ''); break;
  case 'file': text = '[ไฟล์] ' + (msg.fileName || ''); break;
  default: text = '[' + msg.type + ']';
}

const validTypes = ['text','image','video','audio','file','location','sticker'];
const dbType = validTypes.includes(msg.type) ? msg.type : 'text';

return [{
  json: {
    lineUserId: event.source.userId,
    replyToken: event.replyToken,
    messageText: esc(text),
    messageType: dbType,
    messageId: String(msg.id)
  }
}];

const parsed = $('Parse Event').first().json;
let displayName = 'LINE User';
let pictureUrl = '';

try {
  const profile = $('Get LINE Profile').first().json;
  if (profile && profile.displayName) displayName = profile.displayName;
  if (profile && profile.pictureUrl) pictureUrl = profile.pictureUrl;
} catch(e) {}

const esc = (s) => String(s || '').replace(/'/g, "''");

return [{
  json: {
    lineUserId: parsed.lineUserId,
    replyToken: parsed.replyToken,
    messageText: parsed.messageText,
    messageType: parsed.messageType,
    messageId: parsed.messageId,
    displayName: esc(displayName),
    pictureUrl: esc(pictureUrl)
  }
}];
